import{_ as a,c as s,o as i,ag as l}from"./chunks/framework.CkHWihve.js";const T=JSON.parse('{"title":"认证机制和协议 - NTLM","description":"","frontmatter":{},"headers":[],"relativePath":"intranet-security/domain-penetration/认证机制和协议 - NTLM 192b61af428980ee85c2f1b626bfeafc.md","filePath":"intranet-security/domain-penetration/认证机制和协议 - NTLM 192b61af428980ee85c2f1b626bfeafc.md"}'),t={name:"intranet-security/domain-penetration/认证机制和协议 - NTLM 192b61af428980ee85c2f1b626bfeafc.md"};function o(n,e,h,r,d,p){return i(),s("div",null,e[0]||(e[0]=[l(`<h1 id="认证机制和协议-ntlm" tabindex="-1">认证机制和协议 - NTLM <a class="header-anchor" href="#认证机制和协议-ntlm" aria-label="Permalink to &quot;认证机制和协议 - NTLM&quot;">​</a></h1><blockquote><p><a href="https://www.cnblogs.com/yuy0ung/articles/18223233" target="_blank" rel="noreferrer">https://www.cnblogs.com/yuy0ung/articles/18223233</a></p></blockquote><blockquote><p><a href="https://blog.csdn.net/weixin_45954730/article/details/135425628" target="_blank" rel="noreferrer">https://blog.csdn.net/weixin_45954730/article/details/135425628</a> | 细看这个</p></blockquote><h2 id="本地认证" tabindex="-1">本地认证 <a class="header-anchor" href="#本地认证" aria-label="Permalink to &quot;本地认证&quot;">​</a></h2><h3 id="流程" tabindex="-1">流程 <a class="header-anchor" href="#流程" aria-label="Permalink to &quot;流程&quot;">​</a></h3><p>本地认证可以分为大致三个流程</p><ol><li><p>winlogon.exe（Windows Logon Process）接收用户输入的密码</p><p><code>winlogon.exe</code>进程是Windows NT用户登陆程序，用于管理用户登录和退出，用户注销、重启、锁屏后，操作系统会让<code>winlogon.exe</code>显示登录界面。</p></li><li><p>调用lsass.exe (Local Security Authority Service) 进程对用户输入的密码进行加密，转换为<code>HTML Hash</code></p><p>它应用于本地安全和登录策略，这些策略包括密码策略、账户策略、用户权限、域策略等等。同时它还负责对用户进行身份验证以确保只有授权的用户才能访问系统资源。</p><p>除此之外<code>lsass.exe</code>进程的另一个作用是将<strong>收到的明文账号密码在本地内存中保留一份用作备份</strong>，这也就是为什么<code>mimikatz</code>可以抓取低版本系统中的明文密码，但是当系统为<code>Win10</code>或<code>Win server 2012R2</code>以上时，默认在内存缓存中禁止保存明文密码</p></li><li><p>将转换成的<code>NTLM Hash</code>与SAM(Security Account Manager)文件中存储的NTLM Hash进行比较，如相同，将<code>GroupSid</code>与<code>UserSid</code>发送给winlogon.exe准备登陆，如不同则登陆失败</p><p>SAM文件是位于<code>C:\\windows\\system32\\config</code>目录下面，<code>SAM</code>文件是Windows对用户账户的安全管理使用的安全账号管理器，即账号密码数据库文件，存储本地所有用户的凭证信息</p></li></ol><h3 id="lm-hash和ntlm-hash" tabindex="-1"><strong>LM HASH和NTLM HASH</strong> <a class="header-anchor" href="#lm-hash和ntlm-hash" aria-label="Permalink to &quot;**LM HASH和NTLM HASH**&quot;">​</a></h3><p>windows通常对明文密码进行两种方式加密处理<strong>LM HASH</strong>和<strong>NTLM HASH</strong></p><p>Hash在windows中通常 <code>username:RID:LM-HASH:NTLM-HASH</code> 格式</p><ul><li><p>LM HASH</p><p>LM HASH的全名<code>LAN Manager Hash</code>是微软为了提高Windows操作系统的安全性而采用的散列加密算法，**其本质是DES加密。**在windows2008开始默认禁用，LM HASH的明文密码被限定在14位以内，也就是说，如果要停止使用LM HASH，将用户的密码设置为14位以上即可，如果LM HASH被禁用了，攻击者通过工具抓取到的LM HASH通常为<code>aad3b435b51404eead3b435b51404ee</code>(表示LM HASH为空或被禁用</p></li><li><p>NTLM HASH（NT HASH）</p><p>NTLM HASH是微软为了提高安全性的同时保证兼容性而设计的散列加密算法，<strong>NTLM HASH是基于MD4加密算法进行加密</strong></p></li></ul><h3 id="加密步骤" tabindex="-1">加密步骤 <a class="header-anchor" href="#加密步骤" aria-label="Permalink to &quot;加密步骤&quot;">​</a></h3><blockquote><p><a href="https://blog.csdn.net/weixin_45954730/article/details/135425628" target="_blank" rel="noreferrer">https://blog.csdn.net/weixin_45954730/article/details/135425628</a></p></blockquote><h2 id="网络认证" tabindex="-1">网络认证 <a class="header-anchor" href="#网络认证" aria-label="Permalink to &quot;网络认证&quot;">​</a></h2><p>网络认证指windows操作系统中进行网络通信以及资源访问，验证用户和授予身份的过程</p><p>windows网络认证通常分为两种：<code>NTLM</code>以及 <code>kerberos</code>认证</p><h3 id="sspi与ssp的概念" tabindex="-1"><strong>SSPI与SSP的概念</strong> <a class="header-anchor" href="#sspi与ssp的概念" aria-label="Permalink to &quot;**SSPI与SSP的概念**&quot;">​</a></h3><ol><li><p>SSPI （Security Service Provider Interface，安全服务提供接口）是windows定义的一套接口，该接口定义了与安全有关的功能函数，包含但不限于：</p><ul><li>身份验证机制</li><li>为其他协议提供的session security（会话安全）机制</li></ul><p>注意：SSPI只是定义了一套接口函数，并没有实现具体内容</p></li><li><p>SSP （Security Service Provider，安全服务提供者）是SSPI的实现者，例如</p><ul><li>NTLM SSP：Windows NT 3.51中引入（msv1_0.dll），为Windows 2000<strong>之前</strong>的客户端-服务器域和非域身份验证（SMB/CIFS）提供 NTLM 质询/响应身份验证</li><li>Kerberos SSP：Windows 2000中引入，Windows vista中更新为支持AES（kerberos.dll），Windows 2000及更高版本中首选的<strong>客户端-服务器域相互身份验证</strong></li><li>Digest SSP：Windows XP中引入（wdigest.dll），在 Windows 与 kerberos 不可用的非Windows系统间提供基于 HTTP 和 SASL 身份验证的质询/响应</li><li>Negotiate SSP:Windows 2000 中引入（secur32.dll) ，默认选择 Kerberos，如果不可用则选择 NTLM 协议。Negotiate SSP 提供单点登录能力，有时称为集成 Windows 身份验证（尤其是用于 IIS 时)。在 Windows 7 及更高版本中，NEGOExts 引入了协商使用客户端和服务器上 支持的已安装定制 SSP 进行身份验证</li><li>Cred SSP:Windows Vista 中引入，Windows XP SP3 上也可用 （credssp.dll)，为远程桌面连接提供单点登录（SSO)和网络级身份验证</li><li>Schannel SSP:Windows 2000 中引入（Schannel.dll)，Windows Vista 中 更新为支持更强的 AES 加密和 ECC[6] 该提供者使用 SSL/TLS 记录来加密数据有效载荷</li><li>PKU2U SSP:Windows 7 中引入（pku2u.dll) ， 在不隶属域的系统之间提供使用数字证书的对等身份验证</li></ul></li></ol><h3 id="ntlm" tabindex="-1">NTLM <a class="header-anchor" href="#ntlm" aria-label="Permalink to &quot;NTLM&quot;">​</a></h3><p>NTLM身份验证是一种基于<code>Challenge/Response</code>的验证机制，有三种信息组成</p><ol><li>type 1 - 协商 Negotiate：确认双方协议版本，加密等级等</li><li>type 2 - 质询 Challenge ： 服务器接收到客户端协商信息后，会读取其中内容，从中挑取自己能接受的服务内容，加密等级安全服务等。并生成随机数<code>Challenge</code>，然后将其返回给客户端</li><li>type 3 - 认证 Auth ：验证主要在挑战后，认证结果</li></ol><p>并且HTLM协议进行身份验证是，通常有两种情况，本地工作组以及域环境</p><h3 id="ntlm-工作组" tabindex="-1">NTLM - 工作组 <a class="header-anchor" href="#ntlm-工作组" aria-label="Permalink to &quot;NTLM - 工作组&quot;">​</a></h3><ol><li>当客户端需要访问服务器的某个服务时，就需要进行身份认证。于是，当客户端输入服务器的用户名和密码进行验证的时候，客户端就会<strong>缓存服务器密码的NTLM Hash值</strong>。然后，客户端会向服务端发送一个请求，该请求利用<code>NTLM SSP</code> 生成NTLMSSP_NEGOTIATE消息（被称为Type 1 NEGOTIATE 协商消息）</li><li>接下来是<code>Challenge/Response</code>认证机制的关键。服务端接收到客户端发送过来的Type 1消息后，会读取其中的内容，并从中选择出自己所能<strong>接受的服务内容，加密等级，安全服务</strong>等。然后传入NTLM SSP，得到NTLMSSP_CHALLENGE 消息（被称为Type 2 Challenge 质询消息），并将此Type 2消息发回给客户端。此Type 2消息中包含了一个由服务端生成的16位随机值，此随机值被称为<code>Challenge</code>质询值，服务端会将该<code>Challenge</code>质询值缓存起来</li><li>客户端收到服务端返回的Type 2消息后，读取出服务端所支持的内容，并取出其中的<code>Challenge</code>质询值，用<strong>缓存的服务器密码的NTLM Hash</strong>对其进行<strong>加密</strong>得到 <code>Response</code>消息。最后将Response和一些其他信息封装到NTLMSSP_AUTH认证消息中(被称为Type 3 Authenticate认证消息)，发往服务端</li><li>服务端在收到<code>Authenticate</code>认证消息后，从中取出<code>Net-NTLM Hash</code> 。然后用自己密码的NTLM Hash 对Challenge质询值进行一系列加密运算，得到自己计算的Net-NTLM Hash。并比较自己计算出的Net-NTLM Hash 和客户端发送的Net-NTLM Hash是否相等。如果相等，则证明客户端输入的密码正确，从而认证成功，反之则认证失败</li></ol><h3 id="ntlm-域环境" tabindex="-1">NTLM - 域环境 <a class="header-anchor" href="#ntlm-域环境" aria-label="Permalink to &quot;NTLM - 域环境&quot;">​</a></h3><p>NTLM在域环境下的认证和在工作组认证前三步没有什么区别，只是认证的过程需要发送数据到域控上进行认证，所以就有了后面三步</p><ol><li>服务端接收到客户端发送来的 NTLMSSP_AUTH 认证消息后，通过Netlogon协议与域控建立一个安全通道，将验证消息发给域控</li><li>域控收到服务端发来的验证消息后，从中取出Net-NTLM Hash。然后从数据库中找到该用户的NTLM Hash，对<code>Challenge</code>进行一系列加密运算，得到自己计算的Net-NTLM Hash。并比较自己计算出的Net-NTLM Hash和服务端发送的Net-NTLM Hash是否相等，如果相等，则证明客户端输入的密码正确，认证成功，反之认证失败，域控将验证结果发给服务端</li><li>服务端根据DC返回的结果，对客户端进行回复</li></ol><h3 id="分析challenge和response" tabindex="-1">分析Challenge和response <a class="header-anchor" href="#分析challenge和response" aria-label="Permalink to &quot;分析Challenge和response&quot;">​</a></h3><blockquote><p><a href="https://blog.csdn.net/weixin_45954730/article/details/135425628" target="_blank" rel="noreferrer">https://blog.csdn.net/weixin_45954730/article/details/135425628</a></p></blockquote><h3 id="ntmlv1和ntlmv2" tabindex="-1"><strong>NTMLv1和NTLMv2</strong> <a class="header-anchor" href="#ntmlv1和ntlmv2" aria-label="Permalink to &quot;**NTMLv1和NTLMv2**&quot;">​</a></h3><p>NTLM v1身份认证协议和NTLM v2身份认证协议是NTLM身份认证协议的不同版本。目前使用最多的是NTLM v2版本。NTLM v1与NTLM v2最显著的区别就是Challenge质询值的位数与加密算法不同，共同之处就是都是使用的 NTLM Hash进行加密</p><ul><li><p>Challenge质询值</p><p>NTLM v1：8位</p><p>NTLM v2：16位</p></li><li><p>NTLM Hash使用的加密算法：</p><p>NTLM v1：DES加密算法</p><p>NTLM v2：HMAC-MD5加密算法</p></li></ul><p>（感觉NTMLv1好像LM）</p><h3 id="如何计算ntproofstr-net-htlm-hash-和-htlm-vx-hash" tabindex="-1">如何计算NTProofStr（NET HTLM HASH）和 HTLM vx HASH <a class="header-anchor" href="#如何计算ntproofstr-net-htlm-hash-和-htlm-vx-hash" aria-label="Permalink to &quot;如何计算NTProofStr（NET HTLM HASH）和 HTLM vx HASH&quot;">​</a></h3><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">NTProofStr </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> HMAC</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">MD5(challenge </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> blob, NTLMv2 Hash)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">NTLMv2 Hash </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> HMAC</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">MD5(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">unicode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">hex</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">((upper(UserName)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DomainName))), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">NTLM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Hash)</span></span></code></pre></div><h3 id="ntlm-hash-和-htlm-vx-hash的关系" tabindex="-1">NTLM HASH 和 HTLM vx HASH的关系 <a class="header-anchor" href="#ntlm-hash-和-htlm-vx-hash的关系" aria-label="Permalink to &quot;NTLM HASH 和 HTLM vx HASH的关系&quot;">​</a></h3><p><strong>NTLM Hash</strong> 是 Windows 系统中用于存储用户密码的加密形式 <strong>NTLMvX Hash</strong> 是 NTLM 协议（如 NTLMv1 或 NTLMv2）在身份验证过程中生成的临时值</p><h3 id="ntlm-协议存在的安全问题" tabindex="-1">NTLM 协议存在的安全问题 <a class="header-anchor" href="#ntlm-协议存在的安全问题" aria-label="Permalink to &quot;NTLM 协议存在的安全问题&quot;">​</a></h3><p>从NTLM认证的流程中我们可以看到，在Type 3 Auth认证消息中是使用用户密码的Hash计算的。因此当我们没有拿到用户密码的明文而只拿到Hash的情况下，我们可以进行Pass The Hash(PTH)攻击，也就是<strong>哈希传递攻击</strong></p><p>同样，还是在Type3消息中，存在Net-NTLM Hash，当攻击者获得了Net-NTLM Hash后，可以进行中间人攻击，重放Net-NTLM Hash，这种攻击手法也就是大家所说的NTLM Relay(NTLM 中继)攻击。并且由于NTLM v1版本协议加密过程存在天然缺陷，可以对Net-NTLM v1 Hash进行爆破，得到NTLM Hash。拿到NTLM Hash后即可进行横向移动</p><ul><li><p>Pass The Hash</p><p>Pass The Hash(PTH)哈希传递攻击是内网横向移动的一种方式。主要原因是NTLM认证过程中使用的是用户密码的NTLM Hash来进行加密。因此当我们获取到了用户密码的NTLM Hash而没有解出明文时，我们可以利用该NTLM Hash进行哈希传递攻击，对内网其他机器进行Hash碰撞，碰撞到使用相同密码的机器。然后通过135或445端口横向移动到使用该密码的其他机器；</p></li><li><p>NTLM Relay</p><p>NTLM Relay其实严格意义上并不能叫NTLM Relay，而是应该叫 Net-NTLM Relay。它是发生在NTLM认证的第三步，在 Response消息中存在Net-NTLM Hash，当攻击者获得了Net-NTLM Hash后，可以进行中间人攻击，重放Net-NTLM Hash，这种攻击手法也就是大家所说的NTLM Relay(NTLM 中继)攻击。</p></li></ul>`,41)]))}const N=a(t,[["render",o]]);export{T as __pageData,N as default};
